INSERT INTO tasks (id, title, description, status, start_date, due_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('99', '<p>Implement \"Mark as Read\" Feature in Notifications</p>', '<p>User Story: As a user, I need the \"Mark as Read\" button in notifications to function correctly so that I can manage my notifications effectively. Description: Currently, clicking on the \"Mark as Read\" button in notifications does not perform any action. Implement the functionality to mark notifications as read when the button is clicked.</p>', 'Completed', '2024-07-12 00:00:00', '2024-07-19 00:00:00', '1', 'Low', '2024-07-12 11:47:56', '2024-08-13 08:55:51', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, status, start_date, due_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('100', '<p>Google authentication</p>', '<p>Social login/signup</p>', 'Completed', '2024-07-16 00:00:00', '2024-07-23 00:00:00', '1', 'High', '2024-07-15 08:07:47', '2024-08-27 14:42:44', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, status, start_date, due_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('102', 'Make email templates', 'design an email templates for ontezo mails', 'Completed', '2024-07-16 00:00:00', '2024-07-17 00:00:00', '1', 'Low', '2024-07-15 08:31:39', '2024-07-18 12:59:40', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, status, start_date, due_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('103', '<p>Forgot Password</p>', '<p><strong>User Story:</strong> As an admin, I want to reset my password if I forget it so that I can regain access to my account.</p>', 'Completed', '2024-07-19 00:00:00', '2024-07-22 23:59:59', '11', 'Low', '2024-07-15 09:50:52', '2024-10-04 06:55:22', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, slug, story_point, created_by_id) VALUES ('104', '<p>Dashboard Metrics</p>', '<p>As an admin, I want to view various metrics on the dashboard so that I can monitor and analyze the system\''s performance and usage.</p><p><br></p><p><strong>Description: </strong></p><p><br></p><p>Three key metrics</p><ul><li>Total Users</li><li>Total Engagement</li><li>Total Reports</li></ul>'',''Completed'',''2024-07-22 00:00:00'',''2024-07-23 23:59:59'',''11'',NULL,NULL,''[]'',''[]'',NULL,''Low'',''2024-07-15 11:06:29'',''2024-10-04 07:00:01'',NULL,NULL,NULL', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, status, start_date, due_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('3231', 'Implement Login API', '<p>As a user, I want to be able to log in to the system using my credentials, so that I can access my account and perform authorized actions.</p><p><strong>Acceptance Criteria:</strong></p><ul><li>The API should accept a username and password.</li><li>Upon successful login, it should return an authentication token.</li><li>If the credentials are invalid, it should return an appropriate error message.</li><li>If required fields are missing, it should return a validation error.</li></ul><p><br></p>', 'Completed', '2025-01-30 00:00:00', '2025-01-30 23:59:59', 'fc221e37-1fc2-4448-8e89-109265e17814', 'High', '2025-01-30 10:30:09', '2025-04-21 05:15:09', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, slug, story_point, created_by_id) VALUES ('3232', 'List Clients API', '<p>As a user, I want to be able to view a list of all clients, so that I can manage and review client information efficiently.</p><p><strong>Acceptance Criteria:</strong></p><ul><li>The API should return a paginated list of clients.</li><li>It should support query parameters for pagination e.g., page number and limit', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, status, slug, story_point, created_by_id) VALUES ('3233', 'Create New Client API', '<p>As a user, I want to be able to create a new client, so that I can add new clients to the system.</p><p><strong>Acceptance Criteria:</strong></p><ul><li>The API should accept client details such as name, email, and phone number.</li><li>Upon successful creation, it should return the newly created client\''s information.</li><li>If required fields are missing or if the email already exists', 'it should return appropriate error messages.</li></ul><p><br></p>'',''Completed'',''2025-01-30 00:00:00'',''2025-01-30 23:59:59'',''fc221e37-1fc2-4448-8e89-109265e17814'',NULL,NULL,''[\"Backend\"]'',''[]'',NULL,''High'',''2025-01-30 10:32:21'',''2025-04-21 05:14:55'',NULL,NULL,NULL', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, status, start_date, due_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('3234', 'View Client API', '<p>As a user, I want to be able to view detailed information about a specific client, so that I can review and manage individual client records.</p><p><strong>Acceptance Criteria:</strong></p><ul><li>The API should accept a client ID as a parameter.</li><li>It should return detailed information about the specified client.</li><li>If the client ID is invalid or the client does not exist, it should return an appropriate error message.</li></ul><p><br></p>', 'Completed', '2025-01-30 00:00:00', '2025-01-30 23:59:59', 'fc221e37-1fc2-4448-8e89-109265e17814', 'High', '2025-01-30 10:33:11', '2025-04-21 05:14:20', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
