INSERT INTO tasks (id, title, description, status, start_date, due_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('3238', 'Delete Client API', '<p>As a user, I want to be able to delete a client, so that I can remove clients who are no longer active or needed in the system.</p><p><strong>Acceptance Criteria:</strong></p><ul><li>The API should accept a client ID as a parameter.</li><li>Upon successful deletion, it should return a confirmation message.</li><li>If the client ID is invalid or the client does not exist, it should return an appropriate error message.</li></ul><p><br></p>', 'Completed', '2025-01-30 00:00:00', '2025-01-30 23:59:59', 'fc221e37-1fc2-4448-8e89-109265e17814', 'High', '2025-01-30 10:45:49', '2025-04-21 05:14:41', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
