INSERT INTO tasks (id, title, description, status, start_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('6021', 'iOS - \"Password Reset Token Expired\" Error on Change Password Screen After Successful Code Verification', '<p><strong>Description:</strong> After successfully verifying a password reset code, the user encounters a \"Password Reset Token Expired\" error on the \"Change Password\" screen. This prevents the user from setting a new password, despite having already passed the verification step. This error should not occur after successful code verification, and the user should be able to update their password.</p><p><strong>Steps to Reproduce:</strong></p><ol><li>Initiate the password reset process.</li><li>Successfully verify the password reset code.</li><li>Navigate to the \"Change Password\" screen.</li><li>Attempt to set a new password.</li><li>Observe the error message.</li></ol><p><br></p>', 'Completed', '2025-06-13 00:00:00', '912df8f1-f47e-41d7-bc55-a10a76d1892e', 'Low', '2025-06-13 11:54:45', '2025-06-19 10:55:04', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, status, start_date, due_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('6022', 'PR Reviews and code merge for the email template issue', 'PR Reviews and code merge for the email template issue', 'Completed', '2025-06-13 00:00:00', '2025-06-12 23:59:59', '580e4bd4-8fc0-4222-97e8-d40fa0561969', 'Low', '2025-06-13 11:56:22', '2025-06-13 11:58:41', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
INSERT INTO tasks (id, title, description, status, start_date, project_id, priority, created_at, updated_at, slug, story_point, created_by_id) VALUES ('6023', 'iOS -  \"Invalid Prisma Unique Constraints\" Error During Habit Creation', '<p><strong>Description:</strong> The application displays an \"Invalid Prisma Unique Constraints\" error when a user attempts to create a new habit. This error prevents the creation of new habits, a core functionality of the app. This error should be resolved, and users should be able to create new habits without issue.</p><p><strong>Steps to Reproduce:</strong></p><ol><li>Open the application.</li><li>Navigate to the \"Create Habit\" screen.</li><li>Enter the details for a new habit.</li><li>Attempt to save the new habit.</li><li>Observe the error message.</li></ol><p><br></p>', 'Completed', '2025-06-13 00:00:00', '912df8f1-f47e-41d7-bc55-a10a76d1892e', 'Low', '2025-06-13 11:57:29', '2025-06-18 12:48:03', LOWER(REPLACE(title, ' ', '-')), 0.0, 1);
